import type { AnchorHTMLAttributes, MouseEventHandler, ReactElement, ReactNode } from 'react';
import type { TestComponentProps } from 'src/types/test-component';
/**
 * Размер ссылки. Маппинг на типографику: large → body1, medium → body2, small → body3.
 */
export type LinkSize = 'large' | 'medium' | 'small';
/**
 * Значения для aria-current (обозначение текущей ссылки).
 */
export type LinkAriaCurrent = 'page' | 'step' | 'location' | 'date' | 'time' | boolean;
/**
 * Базовые пропсы компонента Link.
 */
export interface LinkBaseProps extends TestComponentProps {
    /**
     * Размер ссылки.
     * @default 'medium'
     */
    size?: LinkSize;
    /**
     * Иконка перед текстом (leading).
     */
    startIcon?: ReactNode;
    /**
     * Иконка после текста (trailing).
     */
    endIcon?: ReactNode;
    /**
     * Цель ссылки (для нативных ссылок с href).
     */
    target?: '_self' | '_blank' | '_parent' | '_top';
    /**
     * Атрибут rel для нативных ссылок.
     */
    rel?: string;
    /**
     * Атрибут download для скачивания.
     */
    download?: boolean | string;
    /**
     * Неактивное состояние.
     * @default false
     */
    disabled?: boolean;
    /**
     * Явное указание visited (для случаев, когда :visited недоступен).
     */
    visited?: boolean;
    /**
     * Содержимое ссылки.
     */
    children: ReactNode;
    /**
     * Пользовательский класс.
     */
    className?: string;
    /**
     * Обработчик клика.
     */
    onClick?: MouseEventHandler<HTMLElement>;
    /**
     * Обработчик фокуса.
     */
    onFocus?: React.FocusEventHandler<HTMLElement>;
    /**
     * Обработчик потери фокуса.
     */
    onBlur?: React.FocusEventHandler<HTMLElement>;
    /**
     * Подпись для screen readers.
     */
    'aria-label'?: string;
    /**
     * Обозначение текущей ссылки (например, в breadcrumbs, nav).
     */
    'aria-current'?: LinkAriaCurrent;
}
/**
 * Пропсы для нативной ссылки (href).
 */
export interface LinkWithHrefProps extends LinkBaseProps, Omit<AnchorHTMLAttributes<HTMLAnchorElement>, 'children' | 'aria-current' | 'download' | 'target' | 'rel' | 'className' | 'onClick' | 'onFocus' | 'onBlur' | 'aria-label'> {
    href: string;
    component?: never;
}
/**
 * Пропсы для SPA-роутинга (component).
 */
export interface LinkWithComponentProps extends LinkBaseProps, Omit<React.HTMLAttributes<HTMLElement>, 'children' | 'aria-current' | 'className' | 'onClick' | 'onFocus' | 'onBlur' | 'aria-label'> {
    component: ReactElement;
    href?: never;
}
/**
 * Пропсы для действия без навигации (Copy, Collapse).
 */
export interface LinkActionProps extends LinkBaseProps {
    href?: never;
    component?: never;
    onClick: MouseEventHandler<HTMLElement>;
}
/**
 * Публичный тип пропсов компонента Link.
 *
 * @example
 * ```tsx
 * // Нативная ссылка
 * <Link href="/page">Страница</Link>
 *
 * // Внешняя ссылка
 * <Link href="https://example.com" target="_blank">Внешний сайт</Link>
 *
 * // React Router
 * <Link component={<Link to="/users">Пользователи</Link>}>Пользователи</Link>
 *
 * // Действие (Copy, Collapse)
 * <Link onClick={handleCopy}>Копировать</Link>
 * ```
 */
export type LinkProps = LinkWithHrefProps | LinkWithComponentProps | LinkActionProps;
